const convertToCelsius = function() {
  function fahrenheitToCelsius (fahrenheit)
  return (fahrenheit - 32) * 5 / 9;
};

const convertToFahrenheit = function() {
  function celciusToFarenheit (celsius)
  return celsius * 9 / 5 + 32;
};

